+
+function camelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+/** Flatten nested config objects and normalise config keys to camel case. */
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = [prefix, camelCase(key)].filter(Boolean).join(".");
+    if (child && typeof child === "object" && !Array.isArray(child)) {
+      Object.assign(values, flattenConfig(child as Record<string, unknown>, name));
+    } else {
+      values[name] = child;
+    }
+  }
+  return values;
+}
+
+/** Parse Cliffy's simple `key=value` RC format. */
+export function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const index = line.indexOf("=");
+    if (index < 0) throw new Error("Expected key=value.");
+    const key = line.slice(0, index).trim();
+    let value = line.slice(index + 1).trim();
+    if (!key) throw new Error("Expected a key.");
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error("Unterminated quoted value.");
+      }
+      value = value.slice(1, -1);
+    } else if (value === "true") {
+      values[camelCase(key)] = true;
+      continue;
+    } else if (value === "false") {
+      values[camelCase(key)] = false;
+      continue;
+    } else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      values[camelCase(key)] = Number(value);
+      continue;
+    }
+    values[camelCase(key)] = value;
+  }
+  return values;
+}
