+function parse(path: string, format: string, content: string, options: ConfigOptions) {
+  try {
+    const value = options.parser
+      ? options.parser(content)
+      : format === ".json"
+      ? JSON.parse(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : (() => { throw new Error("A parser is required for this format."); })();
+    if (!value || typeof value !== "object" || Array.isArray(value)) {
+      throw new Error("Config parser must return a plain object.");
+    }
+    return flattenConfig(value as Record<string, unknown>);
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
