+/** Load config files synchronously. */
+export function loadConfig(options: ConfigOptions): LoadedConfig {
+  const paths = options.searchPaths?.length ? options.searchPaths : [cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const loaded: Array<{ path: string; values: Record<string, unknown> }> = [];
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const path = resolve(join(searchPath, configFileName(options.name, format)));
+      const content = readTextFileSync(path);
+      if (content !== undefined) {
+        loaded.push({ path, values: parse(path, format, content, options) });
+        break;
+      }
+    }
+    if (loaded.length && !options.mergeConfigs) break;
+  }
+  if (!loaded.length) return { values: {} };
+  // Later files supply only values absent from earlier search paths.
+  const values = loaded.reduceRight<Record<string, unknown>>(
+    (result, config) => ({ ...result, ...config.values }),
+    {},
+  );
