+function configKey(name: string): string {
+  return name.replace(/(^|\\.)[^.]*/g, (segment) =>
+    segment[0] === "."
+      ? `.${segment.slice(1).replace(/-([a-zA-Z0-9])/g, (_, c) => c.toUpperCase())}`
+      : segment.replace(/-([a-zA-Z0-9])/g, (_, c) => c.toUpperCase())
+  );
+}
+
+function setConfigValue(
+  values: Record<string, unknown>,
+  key: string,
+  value: unknown,
+): void {
+  const parts = key.split(".");
+  let target = values;
+  for (const part of parts.slice(0, -1)) {
+    target = (target[part] ??= {}) as Record<string, unknown>;
+  }
+  target[parts.at(-1) as string] = value;
+}
+
+function flattenConfigValues(
+  values: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const flattened: Record<string, unknown> = {};
+  for (const [key, value] of Object.entries(values)) {
+    const name = [prefix, key].filter(Boolean).join(".");
+    if (value && typeof value === "object" && !Array.isArray(value)) {
+      Object.assign(flattened, flattenConfigValues(value as Record<string, unknown>, name));
+    } else {
+      flattened[name] = value;
+    }
+  }
+  return flattened;
+}
